165	#[cfg(feature = "codegen")]
166	fn parse_file(content: &str, ext: &str, locale: &str) -> Result<Translations, String> {
167	    let result = match ext {
168	        "yml" | "yaml" => serde_yaml::from_str::<serde_json::Value>(content)
169	            .map_err(|err| format!("Invalid YAML format, {}", err)),
170	        "json" => serde_json::from_str::<serde_json::Value>(content)
171	            .map_err(|err| format!("Invalid JSON format, {}", err)),
172	        "toml" => toml::from_str::<serde_json::Value>(content)
173	            .map_err(|err| format!("Invalid TOML format, {}", err)),
174	        _ => Err("Invalid file extension".into()),
175	    };
176	
177	    match result {
178	        Ok(v) => match get_version(&v) {
179	            2 => {
180	                if let Some(trs) = parse_file_v2("", &v) {
181	                    return Ok(trs);
182	                }
183	
184	                Err("Invalid locale file format, please check the version field".into())
185	            }
186	            _ => Ok(parse_file_v1(locale, &v)),
187	        },
188	        Err(e) => Err(e),
189	    }
190	}
