197	#[cfg(feature = "codegen")]
198	fn parse_file_v2(key_prefix: &str, data: &serde_json::Value) -> Option<Translations> {
199	    let mut trs = Translations::new();
200	
201	    if let serde_json::Value::Object(messages) = data {
202	        for (key, value) in messages {
203	            if let serde_json::Value::Object(sub_messages) = value {
204	                for (locale, text) in sub_messages {
205	                    if text.is_string() {
206	                        let key = format_keys(&[key_prefix, key]);
207	                        let sub_trs = BTreeMap::from([(key, text.clone())]);
208	                        let sub_value = serde_json::to_value(&sub_trs).unwrap();
209	
210	                        trs.entry(locale.clone())
211	                            .and_modify(|old_value| merge_value(old_value, &sub_value))
212	                            .or_insert(sub_value);
213	                        continue;
214	                    }
215	
216	                    if text.is_object() {
217	                        let key = format_keys(&[key_prefix, key]);
218	                        if let Some(sub_trs) = parse_file_v2(&key, value) {
219	                            for (locale, sub_value) in sub_trs {
220	                                trs.entry(locale)
221	                                    .and_modify(|old_value| merge_value(old_value, &sub_value))
222	                                    .or_insert(sub_value);
223	                            }
224	                        }
225	                    }
226	                }
227	            }
228	        }
229	    }
230	
231	    if !trs.is_empty() {
232	        return Some(trs);
233	    }
234	
235	    None
236	}
237	
238	#[cfg(feature = "codegen")]
239	fn get_version(data: &serde_json::Value) -> usize {
240	    if let Some(version) = data.get("_version") {
241	        return version.as_u64().unwrap_or(1) as usize;
242	    }
243	
244	    1
245	}
