247	#[cfg(feature = "codegen")]
248	fn format_keys(keys: &[&str]) -> String {
249	    keys.iter()
250	        .filter(|k| !k.is_empty())
251	        .map(|k| k.to_string())
252	        .collect::<Vec<String>>()
253	        .join(".")
254	}
255	
256	#[cfg(feature = "codegen")]
257	fn flatten_keys(prefix: &str, trs: &Value) -> BTreeMap<String, String> {
258	    let mut v = BTreeMap::<String, String>::new();
259	    let prefix = prefix.to_string();
260	
261	    match &trs {
262	        serde_json::Value::String(s) => {
263	            v.insert(prefix, s.to_string());
264	        }
265	        serde_json::Value::Object(o) => {
266	            for (k, vv) in o {
267	                let key = if prefix.is_empty() {
268	                    k.clone()
269	                } else {
270	                    format!("{}.{}", prefix, k)
271	                };
272	                v.extend(flatten_keys(key.as_str(), vv));
273	            }
274	        }
275	        serde_json::Value::Null => {
276	            v.insert(prefix, "".into());
277	        }
278	        serde_json::Value::Bool(s) => {
279	            v.insert(prefix, format!("{}", s));
280	        }
281	        serde_json::Value::Number(s) => {
282	            v.insert(prefix, format!("{}", s));
283	        }
284	        serde_json::Value::Array(_) => {
285	            v.insert(prefix, "".into());
286	        }
287	    }
288	
289	    v
290	}
