296	    #[test]
297	    fn test_merge_value() {
298	        let a = serde_json::from_str::<serde_json::Value>(
299	            r#"{"foo": "Foo", "dar": { "a": "1", "b": "2" }}"#,
300	        )
301	        .unwrap();
302	        let b = serde_json::from_str::<serde_json::Value>(
303	            r#"{"foo": "Foo1", "bar": "Bar", "dar": { "b": "21" }}"#,
304	        )
305	        .unwrap();
