307	        let mut c = a;
308	        merge_value(&mut c, &b);
309	
310	        assert_eq!(c["foo"], "Foo1");
311	        assert_eq!(c["bar"], "Bar");
312	        assert_eq!(c["dar"]["a"], "1");
