317	    fn test_parse_file_in_yaml() {
318	        let content = "foo: Foo\nbar: Bar";
319	        let mut trs = parse_file(content, "yml", "en").expect("Should ok");
320	        assert_eq!(trs["en"]["foo"], "Foo");
