347	        let content = r#"
348	        foo = "Foo"
349	        bar = "Bar"
350	        "#;
351	        let trs = parse_file(content, "toml", "en").expect("Should ok");
352	        assert_eq!(trs["en"]["foo"], "Foo");
353	        assert_eq!(trs["en"]["bar"], "Bar");
354	    }
355	
356	    #[test]
357	    fn test_get_version() {
358	        let json = serde_yaml::from_str::<serde_json::Value>("_version: 2").unwrap();
359	        assert_eq!(super::get_version(&json), 2);
360	
361	        let json = serde_yaml::from_str::<serde_json::Value>("_version: 1").unwrap();
362	        assert_eq!(super::get_version(&json), 1);
363	
364	        // Default fallback to 1
365	        let json = serde_yaml::from_str::<serde_json::Value>("foo: Foo").unwrap();
366	        assert_eq!(super::get_version(&json), 1);
367	    }
