369	    #[test]
370	    fn test_parse_file_in_json_with_nested_locale_texts() {
371	        let content = r#"{
372	            "_version": 2,
373	            "welcome": {
374	                "en": "Welcome",
375	                "zh-CN": "欢迎",
376	                "zh-HK": "歡迎"
377	            }
378	        }"#;
379	
380	        let trs = parse_file(content, "json", "filename").expect("Should ok");
381	        assert_eq!(trs["en"]["welcome"], "Welcome");
382	        assert_eq!(trs["zh-CN"]["welcome"], "欢迎");
383	        assert_eq!(trs["zh-HK"]["welcome"], "歡迎");
